package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;
import static org.junit.jupiter.api.Assertions.assertThrows;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Arrays;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatValidateTest {

    private CSVFormat csvFormat;
    private Method validateMethod;

    @BeforeEach
    public void setUp() throws NoSuchMethodException, SecurityException {
        csvFormat = CSVFormat.DEFAULT;
        validateMethod = CSVFormat.class.getDeclaredMethod("validate");
        validateMethod.setAccessible(true);
    }

    private void invokeValidate(CSVFormat format) throws Throwable {
        try {
            validateMethod.invoke(format);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    @Test
    public void testValidate_Default_NoException() throws Throwable {
        CSVFormat format = CSVFormat.DEFAULT;
        assertDoesNotThrow(() -> invokeValidate(format));
    }

    @Test
    public void testValidate_DelimiterIsLineBreak_Throws() throws Throwable {
        CSVFormat format = new CSVFormat('\n', null, QuoteMode.MINIMAL, null, null,
                false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("delimiter cannot be a line break"));
    }

    @Test
    public void testValidate_DelimiterEqualsQuoteCharacter_Throws() throws Throwable {
        CSVFormat format = new CSVFormat(',', Character.valueOf(','), QuoteMode.MINIMAL, null, null,
                false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("quoteChar character and the delimiter cannot be the same"));
    }

    @Test
    public void testValidate_DelimiterEqualsEscapeCharacter_Throws() throws Throwable {
        CSVFormat format = new CSVFormat(',', null, QuoteMode.MINIMAL, null, Character.valueOf(','),
                false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("escape character and the delimiter cannot be the same"));
    }

    @Test
    public void testValidate_DelimiterEqualsCommentMarker_Throws() throws Throwable {
        CSVFormat format = new CSVFormat(',', null, QuoteMode.MINIMAL, Character.valueOf(','),
                null, false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("comment start character and the delimiter cannot be the same"));
    }

    @Test
    public void testValidate_QuoteCharacterEqualsCommentMarker_Throws() throws Throwable {
        CSVFormat format = new CSVFormat(',', Character.valueOf('#'), QuoteMode.MINIMAL, Character.valueOf('#'),
                null, false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("comment start character and the quoteChar cannot be the same"));
    }

    @Test
    public void testValidate_EscapeCharacterEqualsCommentMarker_Throws() throws Throwable {
        CSVFormat format = new CSVFormat(',', null, QuoteMode.MINIMAL, Character.valueOf('#'),
                Character.valueOf('#'), false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("comment start and the escape character cannot be the same"));
    }

    @Test
    public void testValidate_NoEscapeCharacterAndQuoteModeNone_Throws() throws Throwable {
        CSVFormat format = new CSVFormat(',', null, QuoteMode.NONE, null,
                null, false, false, "\n", null, null, null, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("No quotes mode set but no escape character is set"));
    }

    @Test
    public void testValidate_HeaderWithDuplicates_Throws() throws Throwable {
        String[] headerWithDup = new String[] { "a", "b", "a" };
        CSVFormat format = new CSVFormat(',', null, QuoteMode.MINIMAL, null,
                null, false, false, "\n", null, null, headerWithDup, false, false, false, false, false);
        IllegalArgumentException ex = assertThrows(IllegalArgumentException.class, () -> invokeValidate(format));
        assert(ex.getMessage().contains("header contains a duplicate entry"));
    }

    @Test
    public void testValidate_HeaderUnique_NoException() throws Throwable {
        String[] uniqueHeader = new String[] { "a", "b", "c" };
        CSVFormat format = new CSVFormat(',', null, QuoteMode.MINIMAL, null,
                null, false, false, "\n", null, null, uniqueHeader, false, false, false, false, false);
        assertDoesNotThrow(() -> invokeValidate(format));
    }

}
